const crypto = require('crypto');

// Generate hardware ID from system info
function getHardwareId() {
  const os = require('os');
  const cpus = os.cpus().map(cpu => cpu.model).join('');
  const platform = os.platform();
  const arch = os.arch();

  const raw = cpus + '|' + platform + '|' + arch;

  // Hash with salt
  return crypto
    .createHash('sha256')
    .update(raw + process.env.HARDWARE_SALT)
    .digest('hex');
}

// Verify license
function verifyLicense(license) {
  const currentHwId = getHardwareId();
  return license.hardware_id === currentHwId;
}

