const fs = require('fs');

function embedAssets(templatePath) {
  let template = fs.readFileSync(templatePath, 'utf8');

  // Embed logo
  const logo = fs.readFileSync('assets/logo.png');
  const logoBase64 = logo.toString('base64');
  template = template.replace(
    '{{LOGO}}',
    'data:image/png;base64,' + logoBase64
  );

  // Embed fonts
  const font = fs.readFileSync('assets/font.woff2');
  const fontBase64 = font.toString('base64');
  template = template.replace(
    '{{FONT}}',
    'data:font/woff2;base64,' + fontBase64
  );

  return template;
}

