from ipaddress import ip_address

# Validate IP without external libraries
def validate_ip(ip_str):
    try:
        ip = ip_address(ip_str)

        # Classify IP type
        if ip.is_private:
            return 'private'
        elif ip.is_loopback:
            return 'loopback'
        elif ip.is_multicast:
            return 'multicast'
        elif ip.is_reserved:
            return 'reserved'
        else:
            return 'public'
    except ValueError:
        return None

# DNS resolution with socket module
def dns_lookup(hostname):
    try:
        return socket.gethostbyname(hostname)
    except socket.gaierror:
        return None
